    text =
    {
        GREETINGS_ADVENTURER_I_M_SO_GLAD_YOU_VE                                            = 0,  -- Greetings adventurer! I'm so glad you've come, kupo! To celebrate the safe recovery of all eleven of King Kupofried's mog tablets, we're offering a limited-time teleportation service for the low, low price of # gil! What do you say?
        TELEPORT_TO_WHERE_COST_GIL_NOWHERE_SAN_D                                           = 1,  -- Teleport to where? (Cost: # gil.) Nowhere. San d'Oria. Bastok. Windurst. Selbina. Mhaura.
        YOUR_WISH_IS_MY_COMMAND_KUPO_FOR_A                                                 = 2,  -- Your wish is my command, kupo! For a small fee of # gil, that is...
        SAFE_TRAVELS_KUPO                                                                  = 3,  -- Safe travels, kupo!
        LOOKS_LIKE_YOU_RE_LIGHT_ON_FUNDS_KUPO                                              = 4,  -- Looks like you're light on funds, kupo... Sorry!
        WHAT_S_THIS_YOU_RE_STILL_NEW_TO                                                    = 5,  -- What's this? You're still new to this land? I'm afraid you're not yet strong enough to handle our potent moogle magic! Just forget I said anything, kupo!
        OH_WHAT_A_SHAME_THE_MOG_TABLETS_HAVE                                               = 6,  -- Oh, what a shame! The mog tablets have been scattered to the winds once more! Without their power, I'm afraid we can't help you, kupo.
        A_HUNT_REGISTRY_HAS_BEEN_PLACED_HERE_BY                                            = 7,  -- A hunt registry has been placed here by the Adventurers' Mutual Aid Network (A.M.A.N.). Its pages are laden with the names of spine-chilling monsters.
        A_HUNT_REGISTRY_HAS_BEEN_PLACED_HERE_BY_2                                          = 8,  -- A hunt registry has been placed here by the Servicemen's Mutual Aid Network (S.M.A.N.). Its pages are laden with the names of spine-chilling monsters.
        WHAT_WILL_YOU_DO_NOTHING_UNDERTAKE_A_HUNT                                          = 9,  -- What will you do? Nothing. Undertake a hunt. Read explanation. Record completion of hunt. View current hunt. Cancel current hunt. View scyld balance.
        YOU_MUST_CANCEL_YOUR_CURRENT_HUNT_IF_YOU                                           = 10,  -- You must cancel your current hunt if you wish to undertake another.
        LITTLE_TIME_HAS_PASSED_SINCE_YOUR_LAST_HUNT                                        = 11,  -- Little time has passed since your last hunt. It is recommended that you take some time to recuperate before undertaking another.
        YOU_CANNOT_UNDERTAKE_A_HUNT_WHILE_A_TRAINING                                       = 12,  -- You cannot undertake a hunt while a training regime is active.
        CANCEL_YOUR_TRAINING_REGIME_YES_NO                                                 = 13,  -- Cancel your training regime? Yes. No.
