        A_FINE_IMAGE_THIS_IS_BUT_THIS_CREATURE                                             = 3157,  -- A fine image this is, but this creature isn't one of my investigation subjects.
        I_FEAR_I_HAVEN_T_THE_TIME_TO                                                       = 3158,  -- I fear I haven't the time to trade pleasantries with random strangers. Please leave me be.
        IS_THERE_SOMETHING_ELSE_YOU_WISH_OF_ME                                             = 3159,  -- Is there something else you wish of me? You already have what you came for, no?
        WE_DON_T_KNOW_WHAT_YOU_RE_DOING                                                    = 3160,  -- We don't know what you're doing here, but truth be told, we're not really interested.
        PUTTING_UP_A_FIGHT_EH_GORATTZ_BOMPUPU_SHOW                                         = 3161,  -- Putting up a fight, eh? Gorattz! Bompupu! Show him/her] what the Tenshodo thinks of meddlesome adventurers!
        D_DAMN_I_M_IN_WAY_OVER_MY                                                          = 3162,  -- D-damn... I'm in way over my head...
        UGH_HE_SHE_S_TOUGHER_THAN_HE_SHE                                                   = 3163,  -- Ugh... He/She]'s tougher than he/she] looks...
        WAAAH_I_DIDN_T_SIGNY_WIGN_UP_FOR                                                   = 3164,  -- Waaah! I didn't signy-wign up for this...
