        THE_FADES_AWAY_INTO_NOTHINGNESS                                                    = 3166,  -- The [Skeleton Scuffler/Blest Bones/Holey Horror/Steely Weapon/Lode Golem/Fired Urn] fades away into nothingness...
        THE_POWER_OF_THE_GREAT_STAR_TREE_HAS                                               = 3167,  -- The power of the Great Star Tree has been released!
        WE_WARMLY_WELCOME_YOU_TO_THE_PLACE_OF                                              = 3168,  -- We warmly welcome you to the place of your unmaking.
        FROM_YOUR_GROUND_BONES_A_LOAF_OF_BREAD                                             = 3169,  -- From your ground bones, a loaf of bread we shall be baking.
