        NAUGHTY_CHILDREN_SHALL_RECEIVE_NO_QUARTER_CURL_UP                                  = 3172,  -- Naughty children shall receive no quarter! Curl up and die, this is your empress's order!
        YOU_VE_LONG_OVERSTAYED_YOUR_WELCOME_THE_PUNISHMENT                                 = 3173,  -- You've long overstayed your welcome! The punishment will be brutal and gruesome!
        WHICH_WAY_DO_YOU_LIKE_IT_SLOW_OR                                                   = 3174,  -- Which way do you like it--slow or fast? Should you lose a limb, be not aghast!
        YOU_LL_WISH_YOU_WERE_NEVER_BORN_FROM                                               = 3175,  -- You'll wish you were never born! From your torso limbs will be torn!
