        BE_THIS_A_DREAM_OR_IS_IT_REAL                                                      = 3180,  -- Be this a dream? Or is it real? This ending falls sorely short of ideal...
        TWAS_HIGH_TIME_YOU_WERE_MADE_TO_KNOW                                               = 3181,  -- 'Twas high time you were made to know that your abilities are purely for show. O`hohohohoho!
        A_FITTING_END_FOR_A_TALENTLESS_CREW_THAT                                           = 3182,  -- A fitting end for a talentless crew that tried to bite off more than it could chew. O`hohohohoho!
        YOUR_BODY_ABSORBS_THE_POWER_HELD_WITHIN_THE                                        = 3183,  -- Your body absorbs the power held within the ancient runes!
        YOU_CANNOT_ENTER_THIS_BATTLEFIELD_WITH_IN_YOUR                                     = 3184,  -- You cannot enter this battlefield with % in your possession.
        IT_APPEARS_YOU_MUST_WAIT_LONGER_TO_COMMENCE                                        = 3185,  -- It appears you must wait longer to commence the battle.
        YOU_ARE_NOT_IN_POSSESSION_OF_UNABLE_TO                                             = 3186,  -- You are not in possession of %. Unable to enter the battlefield for [Sugar-coated Directive/Battaru Royale/Project: Shantottofication].
        YOU_CANNOT_ENTER_THE_BATTLEFIELD_FOR_WITH_IN                                       = 3187,  -- You cannot enter the battlefield for [Sugar-coated Directive/Battaru Royale/Project: Shantottofication] with % in your possession.
