        THE_SAP_CRYSTAL_HAS_NO_EFFECT_MORE_TIME                                            = 3190,  -- The sap crystal has no effect. More time must elapse before you can enter the battlefield for Battaru Royale.
        YOU_ARE_NOT_IN_POSSESSION_OF_A_TABLET                                              = 3191,  -- You are not in possession of a Tablet of Hexes. Unable to enter the battlefield for Project: Shantottofication.
        THE_TABLET_OF_HEXES_HAS_NO_EFFECT_MORE                                             = 3192,  -- The Tablet of Hexes has no effect. More time must elapse before you can enter the battlefield for Project: Shantottofication.
        THE_DOOR_IS_SEALED                                                                 = 3193,  -- The door is sealed.
        YOUR_OPPONENTS_DEEM_YOU_TOO_WEAK_TO_BE                                             = 3194,  -- Your opponents deem you too weak to be worthwhile, disappearing whence they came.
        YOU_RECEIVE_NOTHING_FROM_THE_MOON_RABBIT                                           = 3195,  -- You receive nothing from the moon rabbit...
        THE_MOON_RABBIT_HAS_BROUGHT_ALONG_A_MONSTER                                        = 3196,  -- The moon rabbit has brought along a monster!
        YOU_HAVE_TO_DO_SOMETHING_ABOUT_THOSE_CRAZY                                         = 3197,  -- You have to do something about those crazy trees, kupo!
