        WAIT_A_MOMENT_I_LL_NEED_YOU_TO                                                     = 3286,  -- Wait a moment... I'll need you to rush back to the homeland.
        HERE_YOU_UNDERSTAND_WHAT_YOU_MUST_DO_TAKE                                          = 3287,  -- Here... You understand what you must do? Take this report to the President's Office in Bastok.
        ON_YOUR_WAY_PLEASE_HURRY_TO_BASTOK                                                 = 3288,  -- On your way. Please hurry to Bastok!
        DELIVER_THAT_REPORT_TO_THE_PRESIDENT_S_OFFICE                                      = 3289,  -- Deliver that report to the President's Office in Bastok.
