        I_CONSTANTLY_PRAY_I_PRAY_FOR_THE_FUTURE_2                                          = 3291,  -- I constantly pray. I pray for the future of Bastok.
        AND_I_POLISH_MY_FANGS_IN_CASE_THE                                                  = 3292,  -- And I polish my fangs in case the days of war are near again...
        WHAT_IN_GODDESS_S_NAME_HAPPENED_YOU_CARRIED                                        = 3293,  -- What in Goddess's name happened? You carried out your assignment properly, didn't you? Then why do you look so troubled?
        DON_T_TELL_ME_I_PREFER_NOT_TO                                                      = 3294,  -- Don't tell me. I prefer not to know. It looks like if I heard what you had to say, I wouldn't be able to sleep at night. You better hurry back to our motherland.
