        WHAT_YOU_THOUGHT_YOU_COULD_ACCEPT_MORE_THAN                                        = 3309,  -- What, you thought you could accept more than one mission at a time? If only it was that easy-weasy!
        COMPLETE_YOUR_CURRENT_MISSION_BEFORE_APPLYING_FOR_THE                              = 3310,  -- Complete your current mission before applying for the next.
