        AH_I_NEVER_THOUGHT_THAT_THIS_DAY_WOULD                                             = 11597,  -- Ah, I never thought that this day would come, kupo...
        INDEED_IT_SEEMS_LIKE_JUST_YESTERDAY_THAT_WE                                        = 11598,  -- Indeed, it seems like just yesterday that we first met here.
        I_HAVE_WATCHED_WITH_WONDER_AS_YOU_GREW                                             = 11599,  -- I have watched with wonder as you grew before my very eyes, kupo.
        IN_FACT_I_HEARD_MANY_TALES_OF_YOUR                                                 = 11600,  -- In fact, I heard many tales of your boundless bravery from my friends across the world.
