        THE_SUN_BEATS_DOWN_MERCILESSLY_IN_THE_LAND                                         = 11914,  -- The sun beats down mercilessly in the land beyond the west sea, so I need to take % for my friends there, kupo!
        AND_MY_OTHER_BUDDIES_NEED_FOR_THE_TORRENTIAL                                       = 11915,  -- And my other buddies need % for the torrential rains that scour the lands across the east sea, kupo!
        I_CAN_T_HELP_OUT_MY_FRIENDS_IF                                                     = 11916,  -- I can't help out my friends if I don't have % and %, kupo...
        I_LL_BE_SURE_TO_BRING_YOU_A                                                        = 11917,  -- I'll be sure to bring you a souvenir from my overseas trip, kupo! See you in a few days, master!
        MASTER_I_M_BACK_FROM_VISITING_MY_OLD                                               = 11918,  -- Master! I'm back from visiting my old moogle friends, kupo!
        WE_ALL_GOT_TOGETHER_AND_MADE_YOU_A                                                 = 11919,  -- We all got together and made you a new Mog Safe, kupo! Now you can store as many as 80 items, kupo!
        WHAT_DIDN_T_QUITE_DO_THE_TRICKY_WICKY                                              = 11920,  -- What? % didn't quite do the tricky-wicky? Hmm...
        HOW_ABOUT_TRYING_THAT_PLANT_SMELLS_BAD_ENOUGH                                      = 11921,  -- How about trying %? That plant smells bad enough to raise the dead, so it should work fine on a sleepy-weepy kid.
        I_HEARD_YOU_CAN_FIND_IT_GROWING_IN                                                 = 11922,  -- I heard you can find it growing in the Pashhow Marshlands. Don't forget to take % with you when you go!
        GOOD_LUCK_I_WILL_BESTOW_UPON_YOU_YOUR                                              = 11923,  -- Good luck, [citizen/comrade]. I will bestow upon you your nation's Signet.
        I_CANNOT_HELP_YOU_YOU_SHOULD_GO_FIND                                               = 11924,  -- I cannot help you. You should go find a guard from your own country.
        I_CANNOT_ACCEPT_CRYSTALS_FROM_SOMEONE_WHOSE_RANK                                   = 11925,  -- I cannot accept crystals from someone whose rank is still 1. I advise you to either keep them until your reach rank 2, or to use them in craftwork.
        SINCE_WE_ARE_ALLIED_WITH_SAN_D_ORIA                                                = 11926,  -- Since we are allied with San d'Oria...
        SINCE_WE_ARE_ALLIED_WITH_BASTOK                                                    = 11927,  -- Since we are allied with Bastok...
        SINCE_WE_ARE_ALLIED_WITH_WINDURST                                                  = 11928,  -- Since we are allied with Windurst...
        I_AM_SORRY_I_AM_TOO_BUSY_WITH                                                      = 11929,  -- I am sorry. I am too busy with other matters to be speaking with you.
        AH_YOU_HAVE_BROUGHT_US_SUPPLIES_THESE_WILL                                         = 11930,  -- Ah, you have brought us supplies. These will help us indeed. I thank you.
        HMM_THESE_SUPPLIES_YOU_HAVE_BROUGHT_US_ARE                                         = 11931,  -- Hmm... These supplies you have brought us are too old to be of any use. We will dispose of them promptly. I do commend you for your effort. May you succeed next time.
        YOU_VE_EARNED_CONQUEST_POINTS                                                      = 11932,  -- You've earned conquest points!
        YOU_VE_RECEIVED_YOUR_NATION_S_SIGNET_YOU                                           = 11933,  -- You've received your nation's Signet. You are now taking part in your nation's conquest campaign!
        I_AM_A_TEMPLE_KNIGHT_I_AM_ONE                                                      = 11934,  -- I am , a Temple Knight. I am one of the guards charged with overseeing San d'Oria's conquest campaign.
        I_AM_AN_IRON_MUSKETEER_I_AM_ONE                                                    = 11935,  -- I am , an Iron Musketeer. I am one of the guards charged with overseeing Bastok's conquest campaign.
        I_AM_A_WAR_WARLOCK_I_AM_ONE                                                        = 11936,  -- I am , a War Warlock. I am one of the guards charged with overseeing Windurst's conquest campaign.
        WHAT_IS_YOUR_BUSINESS_WOULD_YOU_CAST_SIGNET                                        = 11937,  -- What is your business? Would you cast Signet on me? I want to spend my conquest points. [I want to join the Expeditionary Force./Teleport me to the E.F. area.] I want to quit the E.F./change my E.F. I want to go on a supplies quest. I have some questions... Nothing, sorry to bother you.
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_NOTHING                                             = 11938,  -- What do you wish to know about? Nothing. Conquests. Conquest results. Donating crystals. Conquest points. The effects of controlling regions. Regions controlled by other nations. Regions under beastman control.
        ALL_THREE_NATIONS_ARE_STRIVING_DAILY_TO_PUT                                        = 11939,  -- All three nations are striving daily to put more regions under their control. This is what we call conquests. You can take part in it and serve your country by defeating enemies while you have Signet cast on you.
        EACH_REGION_COMPRISES_SEVERAL_AREAS_AND_THE_NATION                                 = 11940,  -- Each region comprises several areas, and the nation that rids those areas of the most monsters gains control of the region.
        NATIONS_RECEIVE_GOODS_AND_RESOURCES_FROM_REGIONS_UNDER                             = 11941,  -- Nations receive goods and resources from regions under their control.
        SO_THE_MORE_REGIONS_WE_CONTROL_THE_RICHER                                          = 11942,  -- So, the more regions we control, the richer our nation becomes.
        BORDER_GUARDS_ARE_ALSO_PLACED_IN_OUTPOSTS_WITHIN                                   = 11943,  -- Border guards are also placed in outposts within regions under our control. They are there to cast Signet on adventurers like yourself.
        ONCE_YOU_HAVE_YOUR_NATION_S_SIGNET_YOU                                             = 11944,  -- Once you have your nation's Signet, you will be able to acquire crystals from enemies you defeat.
        NOT_ONLY_THAT_BUT_YOU_WILL_ALSO_RECEIVE                                            = 11945,  -- Not only that, but you will also receive conquest points. You get more conquest points if you defeat enemies in regions that are not under your nation's control. These points can be used to purchase items from guards like myself.
        SO_YOU_SEE_CONQUESTS_BENEFIT_NATIONS_AND_ADVENTURERS                               = 11946,  -- So you see...conquests benefit nations and adventurers alike. We expect you to do your best to serve your country.
        YOU_CAN_SEE_THE_CURRENT_STATE_OF_CONQUESTS                                         = 11947,  -- You can see the current state of conquests by selecting Region Info from the main menu. Conquest results in all regions are regularly recalculated, so you may want to check them from time to time.
        SHOPS_IN_OUR_CITY_WILL_BE_SELLING_DIFFERENT                                        = 11948,  -- Shops in our city will be selling different items according to our conquest rank. The Troupe Valeriano will also visit the nation that finishes first and bring a little joy to its citizens.
        YOU_CAN_DONATE_CRYSTALS_TO_YOUR_NATION_ONCE                                        = 11949,  -- You can donate crystals to your nation once you achieve rank 2. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        WE_WOULD_LIKE_YOU_TO_DONATE_CRYSTALS_TO                                            = 11950,  -- We would like you to donate crystals to your nation from now on. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        YOU_CAN_ACQUIRE_CRYSTALS_BY_DEFEATING_ENEMIES_WHILE                                = 11951,  -- You can acquire crystals by defeating enemies while you have your nation's Signet. Having Signet cast on you is also the only way of taking part in conquests.
        RANK_POINTS_WILL_BE_AWARDED_TO_YOU_FOR                                             = 11952,  -- Rank points will be awarded to you for each crystal you donate, and you may be offered new missions as your rank goes up.
        YOU_ALSO_RECEIVE_RANK_POINTS_FOR_COMPLETING_MISSIONS                               = 11953,  -- You also receive rank points for completing missions. Complete missions and take part in conquests to raise your rank and serve your country.
        YOU_ARE_AWARDED_CONQUEST_POINTS_WHEN_YOU_DEFEAT                                    = 11954,  -- You are awarded conquest points when you defeat monsters while you are taking part in conquests. Select "Region Info" from the menu to check your current number of conquest points.
        YOU_CAN_PURCHASE_ITEMS_FROM_GUARDS_LIKE_MYSELF                                     = 11955,  -- You can purchase items from guards like myself with your conquest points, but be warned that the number of points you spend will be subtracted from your current total.
        WHEN_CONQUEST_RESULTS_ARE_ANNOUNCED_YOU_WILL_BE                                    = 11956,  -- When conquest results are announced, you will be told which country controls the region you are in at that time. Sometimes regions may become neutral, or beastmen may even gain control of regions.
        IF_WE_GAIN_CONTROL_OF_A_REGION_BORDER                                              = 11957,  -- If we gain control of a region, border guards will be placed at its outposts to help adventurers like you.
        MERCHANTS_WILL_ALSO_BE_PLACED_THERE_AND_GOODS                                      = 11958,  -- Merchants will also be placed there, and goods from that region will find their way to the local shops here.
        GAINING_CONTROL_OF_REGIONS_IS_THE_BASIC_PRINCIPLE                                  = 11959,  -- Gaining control of regions is the basic principle behind conquests. We need each of you to do your best, and bring our nation to the top of the ranks.
        OF_COURSE_SOMETIMES_WE_LOSE_REGIONS_TO_OTHER                                       = 11960,  -- Of course, sometimes we lose regions to other nations...so we must try to take them back before the next conquest results are announced.
        AS_AN_INCENTIVE_WE_WILL_AWARD_YOU_WITH                                             = 11961,  -- As an incentive, we will award you with more conquest points for defeating monsters in those regions.
        BUT_IF_WE_ARE_ALLIED_WITH_ANOTHER_NATION                                           = 11962,  -- But if we are allied with another nation, you will only be awarded the regular rate for defeating monsters in our allies' regions. On the other hand, we will award you with more points for fighting in the top-ranked nation's regions.
        OUR_PARAMOUNT_CONCERN_LIES_IN_THE_BEASTMEN_GAINING                                 = 11963,  -- Our paramount concern lies in the beastmen gaining control of our regions. If too many of us are defeated in a region, the beastmen will gain control of it.
        IF_THIS_HAPPENS_NOT_ONLY_IS_IT_A                                                   = 11964,  -- If this happens, not only is it a great blow to our pride, but you will be unable to acquire any crystals in that region.
        THE_BEASTMEN_ARE_A_MENACE_TO_ALL_NATIONS                                           = 11965,  -- The beastmen are a menace to all nations. If they rise to power, we must all unite and drive those vile creatures from that region.
        WE_NEED_YOU_TO_BRING_SUPPLIES_TO_THE                                               = 11966,  -- We need you to bring supplies to the outpost border guards who are placed in regions under our control.
        THERE_IS_ONE_OUTPOST_IN_EACH_REGION_SELECT                                         = 11967,  -- There is one outpost in each region. Select Region Info from the menu, and look for the areas with a small flag mark on the map. That is where they are.
        HERE_ARE_THE_SUPPLIES_JUST_GIVE_THEM_TO                                            = 11968,  -- Here are the supplies. Just give them to the guard at the outpost and your mission will be complete. Now, choose which outpost you want to go to. We give different rewards for each region, so choose carefully.
        WHERE_DO_YOU_WISH_TO_TAKE_THE_SUPPLIES                                             = 11969,  -- Where do you wish to take the supplies? @ @ @ @ @ The Ronfaure Region.[/ (Done)] The Zulkheim Region.[/ (Done)] The Norvallen Region.[/ (Done)] The Gustaberg Region.[/ (Done)] The Derfland Region.[/ (Done)] The Sarutabaruta Region.[/ (Done)] The Kolshushu Region.[/ (Done)] The Aragoneu Region.[/ (Done)] The Fauregandi Region.[/ (Done)] The Valdeaunia Region.[/ (Done)] Qufim Island.[/ (Done)] The Li'Telor Region.[/ (Done)] The Kuzotz Region.[/ (Done)] The Vollbow Region.[/ (Done)] The Elshimo Lowlands Region.[/ (Done)] The Elshimo Uplands Region.[/ (Done)] Tu'Lia.[/ (Done)] @ The Tavnazian Archipelago.[/ (Done)] @ @ @ @ @ @ @ Cancel.
        WHICH_E_F_WOULD_YOU_LIKE_TO_JOIN                                                   = 11970,  -- Which E.F. would you like to join? . . . . . . The Zulkheim Region (Lv.20`). The Norvallen Region (Lv.25`). . The Derfland Region (Lv.25`). . The Kolshushu Region (Lv.20`). The Aragoneu Region (Lv.25`). The Fauregandi Region (Lv.35`). The Valdeaunia Region (Lv.40`). The Qufim Region (Lv.25`). The Li'Telor Region (Lv.35`). The Kuzotz Region (Lv.40`). The Vollbow Region (Lv.65`). The Elshimo Lowlands Region (Lv.35`). The Elshimo Uplands Region (Lv.45`). . . . . . . . . . . None.
        SO_BE_IT_YOU_HAVE_UNTIL_THE_NEXT                                                   = 11971,  -- So be it. You have until the next conquest results announcement to complete this mission. Good luck.
        WE_WILL_DISPOSE_OF_THOSE_UNUSABLE_SUPPLIES                                         = 11972,  -- We will dispose of those unusable supplies.
        YOU_CAN_ONLY_UNDERTAKE_ONE_SUPPLY_MISSION_PER                                      = 11973,  -- You can only undertake one supply mission per day. Come back later.
        I_AM_SORRY_WE_SEEM_TO_HAVE_A                                                       = 11974,  -- I am sorry. We seem to have a problem. Let me cancel it.
        YOU_DO_NOT_NEED_TO_DONATE_ANY_MORE                                                 = 11975,  -- You do not need to donate any more crystals at your current rank. Speak to the guard at the gatehouse for further instructions.
        YOUR_RANK_POINTS_ARE_FULL_WE_VE_ADDED                                              = 11976,  -- Your rank points are full. We've added the excess to your conquest points. You do not need to donate any more crystals. Go to the gatehouse for further instructions.
        GOOD_WORK_CITIZEN_WE_VE_AWARDED_YOU_RANK                                           = 11977,  -- Good work, citizen. We've awarded you rank points for the crystals you've donated.
        YOU_CURRENTLY_HAVE_CONQUEST_POINTS_WOULD_YOU_LIKE                                  = 11978,  -- You currently have # conquest points. Would you like to use them to purchase items?
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_COMMON                                          = 11979,  -- Which item do you wish to purchase? Common items (all ranks). 1000-pt. items (rank 1 required).000-pt. items (rank 2 required). 4000-pt. items (rank 3 required). 8000-pt. items (rank 4 required). 16000-pt. items (rank 5 required).4000-pt. items (rank 6 required).2000-pt. items (rank 7 required). 40000-pt. items (rank 8 required). 48000-pt. items (rank 9 required). 56000-pt. items (rank 10 required). Cancel.
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_COMMON_2                                        = 11980,  -- Which item do you wish to purchase? Common items (all ranks).000-pt. items (rank 1 required). 4000-pt. items (rank 2 required). 8000-pt. items (rank 3 required). 16000-pt. items (rank 4 required).4000-pt. items (rank 5 required).2000-pt. items (rank 6 required). 40000-pt. items (rank 7 required). 48000-pt. items (rank 8 required). 56000-pt. items (rank 9 required). . Cancel.
        CURRENTLY_THERE_ARE_NO_ITEMS_AVAILABLE_FOR_THAT                                    = 11981,  -- Currently there are no items available for that rank.
        DUE_TO_ITS_SPECIAL_NATURE_YOU_CAN_ONLY                                             = 11982,  -- Due to its special nature, you can only purchase or recharge % once until the conquest results tally is performed. Also, you cannot purchase this item if a similar item is already in your possession.
        IT_IS_POSSIBLE_TO_FULLY_RECHARGE_BY_TRADING                                        = 11983,  -- It is possible to fully recharge % by trading it to one of your nation's guards, including outpost guards. One charge requires 50 conquest points.
        IT_IS_POSSIBLE_TO_FULLY_RECHARGE_BY_TRADING_2                                      = 11984,  -- It is possible to fully recharge % by trading it to one of your nation's guards, including outpost guards. One charge requires 100 conquest points.
        IT_IS_POSSIBLE_TO_FULLY_RECHARGE_BY_TRADING_3                                      = 11985,  -- It is possible to fully recharge % by trading it to one of your nation's guards, including outpost guards. One charge requires 200 conquest points.
        DURING_THE_TIME_OF_THE_GREAT_WAR_IT                                                = 11986,  -- During the time of the Great War, it was possible to have this item recharged in exchange for Allied Notes. From my understanding, that practice has recently become commonplace in the Near East. Though you'll be needing Imperial Standing credits if you wish to use the service there.
        YOU_DO_NOT_POSSESS_THE_REQUIRED_TO_FULLY                                           = 11987,  -- You do not possess the # [conquest point/conquest points] required to fully recharge the %.
        PLEASE_BE_AWARE_THAT_YOU_CAN_ONLY_PURCHASE                                         = 11988,  -- Please be aware that you can only purchase or recharge % once during the period between each conquest results tally.
        THE_IS_ALREADY_FULLY_CHARGED                                                       = 11989,  -- The % is already fully charged.
        YOUR_HAS_RECEIVED_IN_EXCHANGE_FOR_IT_IS                                            = 11990,  -- Your % has received # [charge/charges] in exchange for # [conquest point/conquest points]. It is now fully recharged.
        I_WILL_TRADE_YOU_FOR_YOUR_MAY_IT                                                   = 11991,  -- I will trade you % for your %. May it serve you well.
        YOU_DO_NOT_MEET_THE_REQUIREMENTS_TO_PURCHASE                                       = 11992,  -- You do not meet the requirements to purchase the %.
        YOUR_RANK_IS_TOO_LOW_TO_PURCHASE_THE                                               = 11993,  -- Your rank is too low to purchase the %.
        YOU_DO_NOT_HAVE_ENOUGH_CONQUEST_POINTS_TO                                          = 11994,  -- You do not have enough conquest points to purchase the %.
        YOU_CANNOT_EQUIP_THE_DO_YOU_STILL_WISH                                             = 11995,  -- You cannot equip the %. Do you still wish to proceed?
        YOUR_LEVEL_IS_TOO_LOW_TO_EQUIP_THE                                                 = 11996,  -- Your level is too low to equip the %. Do you still wish to proceed?
        YOU_SEEM_TO_BE_ABLE_TO_EQUIP_THE                                                   = 11997,  -- You seem to be able to equip the %. Do you wish to proceed?
        ARE_YOU_SURE_YOU_WANT_TO_PURCHASE_THE                                              = 11998,  -- Are you sure you want to purchase the %?
        PROCEED_YES_PURCHASE_ITEM_CANCEL_PURCHASE                                          = 11999,  -- Proceed? Yes, purchase item. Cancel purchase.
        PROCEED_YES_EVEN_THOUGH_I_CAN_T_EQUIP                                              = 12000,  -- Proceed? Yes, even though I can't equip it. Cancel purchase.
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_NEXT                                            = 12001,  -- Which item do you wish to purchase? %. %. %. %. %. %. %. %. Next page. Previous page. Back.
        WHICH_ITEM_DO_YOU_WISH_TO_PURCHASE_PTS                                             = 12002,  -- Which item do you wish to purchase? %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. %...# pts. Next page. Previous page. Back.
        ENDPARAF                                                                           = 12003,  -- ENDPARAF#
        WHICH_SERVICE_DO_YOU_REQUEST_BUY_SELL_ITEMS                                        = 12004,  -- Which service do you request? Buy/Sell items. Teleportation. Nothing.
        DO_YOU_REALLY_WISH_TO_BE_TELEPORTED_YES                                            = 12005,  -- Do you really wish to be teleported? Yes. Teleport with gil. Teleport with conquest points. No.
        WELCOME_TO_THE_BORDER_SHOP_IF_YOU_TRADE                                            = 12006,  -- Welcome to the border shop! If you trade me unused equipment, I'll add their value to your country's region points!
        IT_SHOULD_PLEASE_YOU_TO_KNOW_THAT_I                                                = 12007,  -- It should please you to know that I now also deal in %. Bigger pieces will earn you more points for your nation, and I'll even toss some gil into the equation!
        I_SEE_THAT_YOUR_HOME_COUNTRY_HAS_CONTROL                                           = 12008,  -- I see that your home country has control of this region. Feel free to browse through my wares.
        I_SEE_THAT_YOUR_HOME_COUNTRY_IS_ALLIES                                             = 12009,  -- I see that your home country is allies with the country in control of this region. Feel free to browse through my wares.
        I_CAN_TELEPORT_YOU_TO_YOUR_HOME_COUNTRY                                            = 12010,  -- I can teleport you to your home country for # gil or # conquest [point/points].
        WORD_HAS_IT_THAT_THE_ENTIRE_SET_OF                                                 = 12011,  -- Word has it that the entire set of mog tablets has been recovered. Oh, happy day! In honor of the occasion, I can teleport you to your home country free of charge.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS                                                = 12012,  -- I am terribly sorry, but it seems as if you do not have enough gil.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS_2                                              = 12013,  -- I am terribly sorry, but it seems as if you do not have enough conquest points.
        HOWEVER_DUE_TO_YOUR_HOME_COUNTRY_S_LACK                                            = 12014,  -- However, due to your home country's lack of influence in the region, this is the only transaction I am authorized to perform with you at the moment.
        I_AM_LOOKING_FORWARD_TO_DOING_BUSINESS_WITH                                        = 12015,  -- I am looking forward to doing business with you again in the future!
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S                                         = 12016,  -- Thank you. This will increase your nation's region points by a small amount. If you have anything else, by all means, trade them to me.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_2                                       = 12017,  -- Thank you. This will increase your nation's region points moderately. If you have anything else, by all means, trade them to me.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_3                                       = 12018,  -- Thank you. This will increase your nation's region points greatly. If you have anything else, by all means, trade them to me.
        I_COULD_NOT_ACCEPT_ONE_OR_MORE_ITEMS                                               = 12019,  -- I could not accept one or more items you tried to trade me. Please remove those items and try again.
        SORRY_I_CAN_ONLY_TAKE_CERTAIN_TYPES_OF                                             = 12020,  -- Sorry. I can only take certain types of weapons, shields, or armor.
        THANK_YOU_THIS_WILL_INCREASE_YOUR_NATION_S_4                                       = 12021,  -- Thank you. This will increase your nation's region points [by a small amount/moderately/greatly]. For this transaction I will also furnish you with # gil.
        MY_APOLOGIES_BUT_THIS_TYPE_OF_ITEM_NEEDS                                           = 12022,  -- My apologies, but this type of item needs to be individually appraised. Please trade them to me one at a time.
        DEBUG_BACK_TO_HOMETOWN                                                             = 12023,  -- (DEBUG) Back to hometown!
        WHAT_DO_YOU_WANT_WOULD_YOU_CAST_SIGNET                                             = 12024,  -- What do you want? Would you cast Signet on me? I'd like to set my home point here. Nothing.
        WHAT_DO_YOU_WANT_PAY_GIL_AND_SET                                                   = 12025,  -- What do you want? Pay # gil and set my home point here. Nothing.
        YOUR_HOME_POINT_HAS_BEEN_SET                                                       = 12026,  -- Your home point has been set.
        YOU_DO_NOT_HAVE_ENOUGH_GIL_TO_SET                                                  = 12027,  -- You do not have enough gil to set your home point here.
        I_WILL_SET_YOUR_HOME_POINT_HERE                                                    = 12028,  -- I will set your home point here.
        WE_ARE_CURRENTLY_ON_A_BEASTMAN_PURGING_CAMPAIGN                                    = 12029,  -- We are currently on a beastman-purging campaign. We support adventurers from all nations. Do your best to rid the world of those vile creatures.
        WE_ARE_CURRENTLY_CONDUCTING_AN_INTERNATIONAL_EXCHANGE_CAMPAIGN                     = 12030,  -- We are currently conducting an international exchange campaign. You may spend your conquest points to purchase items from foreign guards.
        THANKS_TO_YOU_OUR_NATION_IS_NOW_FIRST                                              = 12031,  -- Thanks to you, our nation is now first in the conquest race! Here is a small token of our appreciation.
        ADVENTURERS_FROM_NATIONS_THAT_ARE_RANKED_HIGHER_THAN                               = 12032,  -- Adventurers from nations that are ranked higher than ours in the conquest race may purchase items from us, but at a higher rate.
        YOU_CANNOT_CURRENTLY_PURCHASE_THIS_ITEM_PLEASE_CHOOSE                              = 12033,  -- You cannot currently purchase this item. Please choose another.
        CURRENTLY_OUR_NATION_IS_DISPATCHING_EXPEDITIONARY_FORCES_ACROSS                    = 12034,  -- Currently our nation is dispatching Expeditionary Forces across Vana'diel, and requests the participation of brave adventurers such as yourself.
        REQUIREMENTS_FOR_PARTICIPATING_IN_AN_E_F_ARE                                       = 12035,  -- Requirements for participating in an E.F. are simple. Your party must consist of # members. Each member must be from this country, rank 3 or higher, and have reached a sufficient level.
        ONCE_YOUR_PARTY_IS_READY_COME_TO_ME                                                = 12036,  -- Once your party is ready, come to me and I will teleport you to the nearest outpost.
        THERE_YOU_WILL_RECEIVE_AN_INSIGNIA_OF_THE                                          = 12037,  -- There, you will receive an insignia of the Expeditionary Force. When you succeed in taking control of the area, you can exchange the insignia for your reward.
        JOIN_THE_E_F_IN_JOIN_THE_E                                                         = 12038,  -- Join the E.F. in [Ronfaure/Zulkheim/Norvallen/Gustaberg/Derfland/Sarutabaruta/Kolshushu/Aragoneu/Fauregandi/Valdeaunia/Qufim/Li'Telor/Kuzotz/Vollbow/The Elshimo Lowlands/The Elshimo Uplands]? Join the E.F. Not this time.
        YOUR_PARTY_DOESN_T_HAVE_ENOUGH_MEMBERS_OR                                          = 12039,  -- Your party doesn't have enough members, or some of the members are not in this area. Gather all those who are participating and return here.
        ONE_OF_YOUR_PARTY_MEMBERS_IS_NOT_A                                                 = 12040,  -- One of your party members is not a citizen of this country. We do not allow any foreign participants in the E.F.
        ONE_OF_YOUR_PARTY_MEMBERS_HAS_NOT_ACHIEVED                                         = 12041,  -- One of your party members has not achieved rank level 3. We cannot reveal any of our tactical strategies to those who have not shown their loyalty to our country.
        ONE_OF_YOUR_PARTY_MEMBERS_IS_BELOW_LEVEL                                           = 12042,  -- One of your party members is below level #. For the safety of the adventurer and those accompanying him or her, we cannot allow anyone below the limit to participate in the E.F.
