        OH_THE_AIRSHIP_HAS_ALREADY_LEFT_I_GUESS                                            = 12811,  -- Oh, the airship has already left... I guess we'll just have to leave this with the airship authorities.
        YOU_WERE_UNABLE_TO_MEET_WITH_THE_RIGHTFUL                                          = 12812,  -- You were unable to meet with the rightful owner of the item? Well, thank you for your help, in any case. I will hand the item over to the airship authorities.
        WHAT_YOU_VE_FORGOTTEN_ALREADY                                                      = 12813,  -- What, you've forgotten already?
        HAVE_YOU_FORGOTTEN_YES_NO                                                          = 12814,  -- Have you forgotten? Yes. No.
