        IT_S_MY_JOB_TO_LOOK_OUT_FOR                                                        = 12816,  -- It's my job to look out for suspicious characters coming in on the airships.
        THE_IRNC_HAS_DISPATCHED_ME_TO_HELP_SUPPORT                                         = 12817,  -- The IRNC has dispatched me to help support all those who wish to participate in Conflict.
        BEFORE_YOU_CAN_TAKE_PART_IN_THIS_CONFLICT                                          = 12818,  -- Before you can take part in this Conflict event, you must first possess %. You can obtain one from your nation's Conflict Commander, [Excenmille, stationed in Northern San d'Oria./Invincible Shield, stationed in the Metalworks in Bastok./Mhabi Molkot, stationed in Heavens Tower in Windurst.]
        ONLY_ADVENTURERS_WHO_HAVE_ACHIEVED_RANK_3_OR                                       = 12819,  -- Only adventurers who have achieved rank 3 or higher may take part in official Ballista matches. Please return when you have proven your loyalty to your home nation.
        HOWEVER_IF_YOU_STILL_WISH_TO_TAKE_PART                                             = 12820,  -- However, if you still wish to take part in Ballista, participation in matches held within Diorama Abdhaljs-Ghelsba is open to all citizens of Vana'diel.
        WHAT_SERVICES_DO_YOU_REQUIRE                                                       = 12821,  -- What services do you require?
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_THE                                               = 12822,  -- What can I help you with? Nothing. The upcoming Ballista matches. The Ballista schedule. A teleport to the Ballista match. The rules of Ballista. Borrow/Return %. Borrow/Return %. Borrow/Return %. The upcoming Brenner matches. A teleport to the Brenner match (Lv #). The rules of Brenner. Borrow/Return %. Borrow/Return %.
        I_AM_ALLOWED_TO_TELEPORT_BALLISTA_PARTICIPANTS_TO                                  = 12823,  -- I am allowed to teleport Ballista participants to the site of the next match in exchange for % or # Ballista [Point/Points]. This service is available from twenty-four hours before the start of the match, up until the end of the match.
        CAN_BE_RECEIVED_AFTER_PARTICIPATING_IN_BALLISTA_OR                                 = 12824,  -- % can be received after participating in Ballista, or in the event one is not able to participate due to an influx (or lack) of entries.
        I_M_SORRY_BUT_I_AM_NOT_AUTHORIZED                                                  = 12825,  -- I'm sorry, but I am not authorized to teleport persons who do not meet the level requirement for the match.
        THE_FOLLOWING_INFORMATION_REGARDS_THE_MATCH_I_AM                                   = 12826,  -- The following information regards the match I am currently authorized to teleport you to...
        TELEPORT_RIGHT_AWAY_NOT_YET                                                        = 12827,  -- Teleport? Right away. Not yet.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU                                               = 12828,  -- I am sorry, but I cannot teleport you at this time.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU_2                                             = 12829,  -- I am sorry, but I cannot teleport you at this time. Please return when there are less than twenty-four hours remaining until the next match.
        CURRENTLY_THE_FOLLOWING_SPECIAL_RULES_ARE_BEING_IMPLEMENTED                        = 12830,  -- Currently, the following special rules are being implemented...
        CURRENTLY_THERE_ARE_NO_SPECIAL_RULES_BEING_IMPLEMENTED                             = 12831,  -- Currently, there are no special rules being implemented.
        THE_NEXT_SCHEDULED_BALLISTA_MATCH_IS_AREA_MATCHUP                                  = 12832,  -- The next scheduled Ballista match is: Area: [Jugner Forest/Pashhow Marshlands/Meriphataud Mountains] Matchup: [San d'Oria vs Bastok/Bastok vs Windurst/Windurst vs San d'Oria] Level Restriction: [None/@/@/30/40/50/60/] Participation Fee: # gil Match Format: [All or Nothing * Normal Items Allowed/All or Nothing * Normal Items Restricted/Best of Three * Normal Items Allowed]
        ENTRIES_ARE_NOW_BEING_ACCEPTED                                                     = 12833,  -- Entries are now being accepted.
