        WHILE_WEARING_DURING_A_MATCH_YOU_WILL_BE                                           = 12836,  -- While wearing % during a match, you will be able to hear the orders of your nation's Pursuivant. His advice will aid you in battle.
        ALSO_YOU_WILL_BE_INFORMED_OF_ALL_THE                                               = 12837,  -- Also, you will be informed of all the latest match information when entering select cities.
        WOULD_YOU_LIKE_YES_NO                                                              = 12838,  -- Would you like %? Yes. No.
        RETURN_YOUR_YES_NO                                                                 = 12839,  -- Return your %? Yes. No.
        OBTAINED_3                                                                         = 12840,  -- Obtained: %.
        BY_CARRYING_WITH_YOU_DURING_A_BALLISTA_MATCH                                       = 12841,  -- By carrying % with you during a Ballista match, any temporary item you quarry will be automatically placed in your bag without you having to select whether you wish to keep it, use it, or throw it away.
        WHEN_YOUR_INVENTORY_IS_FULL_OR_YOU_CANNOT                                          = 12842,  -- When your inventory is full, or you cannot carry any more of a certain item, the newly quarried item will be automatically discarded. If you wish, I can lend you one of these shovels, free of charge.
        BORROW_YES_NO                                                                      = 12843,  -- Borrow %? Yes. No.
        YOU_BORROW                                                                         = 12844,  -- You borrow %!
        RETURN_THE_YES_NO                                                                  = 12845,  -- Return the %? Yes. No.
        YOU_RETURN_THE                                                                     = 12846,  -- You return the %!
        WHEN_CARRYING_WITH_YOU_WHILE_PARTICIPATING_IN_A                                    = 12847,  -- When carrying % with you while participating in a Ballista match, you will have the option to keep or throw away the first Petra you find. This is useful when you want to continue /sprinting.
        IF_YOU_WISH_I_CAN_LOAN_YOU_ONE                                                     = 12848,  -- If you wish, I can loan you one, free of charge.
        BORROW_YES_NO_2                                                                    = 12849,  -- Borrow %? Yes. No.
        RETURN_THE_YES_NO_2                                                                = 12850,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_TEMPORARY                                       = 12851,  -- When in possession of the key item %, temporary items will be automatically added to the player's inventory when quarried.
        WHEN_A_PLAYER_S_INVENTORY_EXCEEDS_THE_MAXIMUM                                      = 12852,  -- When a player's inventory exceeds the maximum capacity, any temporary item found will simply be discarded. You can speak to me to borrow or return the shovel at any time.
        BORROW_THE_YES_NO                                                                  = 12853,  -- Borrow the %? Yes. No.
        RETURN_THE_YES_NO_3                                                                = 12854,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_YOU                                             = 12855,  -- When in possession of the key item %, you will have the choice of keeping or throwing away the first Petra you quarry. You will also retain the ability to sprint.
        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                                   = 12856,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                                            = 12857,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                                            = 12858,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                                          = 12859,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                              = 12860,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                                     = 12861,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                                        = 12862,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                                     = 12863,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                            = 12864,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                                          = 12865,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                                  = 12866,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                              = 12867,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                                  = 12868,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                               = 12869,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                                          = 12870,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                                     = 12871,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE                           = 12872,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                                       = 12873,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                                     = 12874,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                                      = 12875,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY                        = 12876,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                                 = 12877,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                                        = 12878,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                                 = 12879,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                            = 12880,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                                          = 12881,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                                      = 12882,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                                        = 12883,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                            = 12884,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                                      = 12885,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                              = 12886,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                                       = 12887,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                                = 12888,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                                           = 12889,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                                      = 12890,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                                          = 12891,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                                 = 12892,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        EXTRA_EXTRA_HEAR_ALL_ABOUT_IT_T_MAGIC_3                                            = 12893,  -- Extra! Extra! Hear all about it!t Magic Paradise Weekly is chock-a-block full of the latest news in Windu`rst!t The next special feature is...
        HUH_THREE_TARUTARU_WEARING_CLOTHING_FROM_ANOTHER_COUNTRY                           = 12894,  -- Huh? Three Tarutaru wearing clothing from another country? How come you know all aboutaru our next special feature?
        IF_YOU_RE_LOOKING_FOR_THEM_THEY_WERE                                               = 12895,  -- If you're looking for them, they were justaru sitting on top of the air travel agency, sighing as they watched the airships come and go.
        THOSE_BIG_BOATS_ARE_CALLED_AIRSHIPS_RIGHT                                          = 12896,  -- Those big boats are called airships, right?
        I_WONDER_IF_ONE_OF_THOSE_COULD_TAKE                                                = 12897,  -- I wonder if one of those could take us home.
        BUT_AS_SOON_AS_WE_GET_HOME_WE                                                      = 12898,  -- But as soon as we get home we're gonna be in big trouble.
        PRISHE_IS_NEVER_LAZY_WITH_HER_PUNISHMENTS_EITHER                                   = 12899,  -- ... Prishe is never lazy with her punishments, either.
        NOPE_SHE_DEFINITELY_DOESN_T_HOLD_BACK                                              = 12900,  -- ... Nope, she definitely doesn't hold back.
        SHE_REALLY_GETS_UGLY_THAT_S_FOR_SURE                                               = 12901,  -- She really gets ugly, that's for sure.
        YOU_KNOW_I_VE_BEEN_THINKING                                                        = 12902,  -- You know, I've been thinking...
        I_DON_T_THINK_THAT_GUY_WAS_OUR                                                     = 12903,  -- I don't think that guy was our father.
        NAH_NOT_OUR_DAD                                                                    = 12904,  -- Nah, not our dad.
        NOPE_NOT_OUR_DADDY                                                                 = 12905,  -- Nope, not our daddy.
        OUR_FATHER_WOULD_BE_SOMEONE_A_LOT_MORE                                             = 12906,  -- Our father would be someone a lot more powerful.
        YEAH_HE_IS_OUR_DAD_AFTER_ALL                                                       = 12907,  -- Yeah, he is our dad, after all.
        OUR_DADDY_WOULD_HAVE_TO_BE_A_SUPER                                                 = 12908,  -- Our daddy would have to be a super-duper, double-whammy, extra-wizzy wizard.
        FATHER                                                                             = 12909,  -- Father!
        DAD                                                                                = 12910,  -- Dad!
        DADDY                                                                              = 12911,  -- Daddy!
        AND_THEN_THEY_WENTARU_LOOKING_FOR_A_SUPER                                          = 12912,  -- ...And then they wentaru looking for a super-duper, double-whammy, extra-wizzy wizard somewhere in Windurst Waters.
        EXTRA_EXTRA_HEAR_ALL_ABOUT_IT_T_THIS                                               = 12913,  -- Extra! Extra! Hear all about it!t This has been a Windurst news update from your friendly Magic Paradise Weekly journalist!t
        DON_T_TELL_ANYBODY_BUT_I_VE_MANAGED                                                = 12914,  -- Don't tell anybody, but I've managed to get my hands on some items from Tavnazia! Take a look!
        PSSST_HAVE_YOU_HEARD_OF_TAVNAZIA_BOY_DO                                            = 12915,  -- Pssst! Have you heard of Tavnazia? Boy, do they have some sweet items on those islands...
        IT_WON_T_BE_LONG_BEFORE_I_SET                                                      = 12916,  -- It won't be long before I set up shop right here in this very place. And once I start, there won't be no stoppin' me!
        AVAST_THERE_MATEY_YE_WANNA_GO_A_ROUND                                              = 12917,  -- Avast there, matey! Ye wanna go a round of fisticuffs? I be in the mood for a fight!
        IN_BIBIKI_BAY_THERE_BE_A_PLACE_KNOWN                                               = 12918,  -- In Bibiki Bay there be a place known as Purgonorgo Isle. On this island lives a mighty strange character that won't listen to a word we has to say.
        ALL_THE_ISLANDS_IN_THAT_BAY_BELONG_TO                                              = 12919,  -- All the islands in that bay belong to us here at the Fishermen's Guild, but that scurvy-wurvy dog insists that Purgonorgo Isle be his, an' his alone.
        WE_VE_TRIED_TALKING_IT_OUT_ALL_CIVIL                                               = 12920,  -- We've tried talking it out all civil-like, but things have gotten out o' hand. We've even been settin' monsters on each other in place of talking... Who knows what we'll be facing next!
        NOW_HANG_ON_A_MOMENT_THERE_MATEY_SURELY                                            = 12921,  -- Now, hang on a moment there, matey. Surely being an adventurer an' all, ye could put that mangy piece o' shark bait in his place. Ye go see if ye can talk some sense into him!
        GO_TALK_SENSE_SURE_MATEY_NOT_TODAY_MATEY                                           = 12922,  -- Go talk sense? Sure, matey. Not today, matey.
        WE_LOST_OUR_LAST_ENCOUNTER_SO_IF_THE                                               = 12923,  -- We lost our last encounter, so if the Fishermen's Guild doesn't win this next round, our name'll be mud on the high seas!
        THE_NEXT_DEBATE_IS_SET_TO_TAKE_PLACE                                               = 12924,  -- The next debate is set to take place in the middle o' Purgonorgo Isle. Don't ye be losing now, matey!
        THAT_WARMACHINE_SLIPPED_YOU_THIS                                                   = 12925,  -- That warmachine slipped you this %?
        IT_DON_T_MATTER_HOW_MANY_PIECES_OF                                                 = 12926,  -- It don't matter how many pieces of trash he hands over, we won't be giving in!
        IT_LOOKS_TO_ME_LIKE_A_DEED_WRITTEN                                                 = 12927,  -- It looks to me like a deed written in Mithran style. That kinda feline legal jargon-wargon's got nothing to do with us Tarutaru.
        HE_S_TELLING_US_TO_TAKE_OUR_BATTLE                                                 = 12928,  -- He's telling us to take our battle to the Mithra boss!
        JUST_A_FISH_PICKIN_MINUTE_THERE_IF_THIS                                            = 12929,  -- Just a fish-pickin' minute there. If this has somethin' to do with Mithra, then I better have a look at it...
        GUILDMASTER                                                                        = 12930,  -- Guildmaster!
        A_MITHRAN_TRACKER_HAPPENS_TO_BE_IN_ATTOHWA                                         = 12931,  -- ... A Mithran Tracker happens to be in Attohwa Chasm this verrry moment.
        YA_DON_T_LOOK_RRREAL_BUSY_WHY_DON                                                  = 12932,  -- Ya don't look rrreal busy. Why don't ya head on over therrre and show this to her?
        SHE_SHOULD_BE_ABLE_TO_TELL_US_IF                                                   = 12933,  -- She should be able to tell us if this % is the rrreal deal. Off ya go.
        GET_YERSELF_TO_ATTOHWA_CHASM_AN_FIND_THAT                                          = 12934,  -- Get yerself to Attohwa Chasm an' find that Mithran Tracker. She should be able to tell us if it's the real deal.
        THAT_PAPER_SMELLS_KINDA_FISHY_I_M_TELLING                                          = 12935,  -- That paper smells kinda fishy. I'm telling ye, it's a fake!
        YE_RE_BACK_MATEY_WHAT_DID_YE_FIND                                                  = 12936,  -- Ye're back, matey. What did ye find out?
        HRM_SO_THIS_TURNED_OUT_TO_BE_A                                                     = 12937,  -- Hrm... So this turned out to be a pirrrate's tale after all. Better for us to keep our whiskers clean of this one.
        WHAT_NONSENSE_BE_YOU_SPEAKING_THIS_NOT_BE                                          = 12938,  -- What nonsense be you speaking!? This not be the guildmaster I know!
        AIN_T_YE_ALWAYS_TELLING_US_THERE_S                                                 = 12939,  -- Ain't ye always telling us there's no place on the seas fer a coward!?
        IT_S_NOT_THE_PIRRRATES_I_M_AFRAID                                                  = 12940,  -- It's not the pirrrates I'm afraid of. This herrre dispute could escalate into a prrroblem between Windurst and Kazham.
        YOU_BE_TALKING_DAFT                                                                = 12941,  -- You be talking daft!
        THERE_S_BEEN_TIES_BETWEEN_WINDURST_AND_THE                                         = 12942,  -- There's been ties between Windurst and the Mithran pirates for a good long while now. Little arrrguments like this one have come close to causing full-scale war.
        AND_SINCE_NONE_OF_US_WANT_TO_CAUSE                                                 = 12943,  -- And since none of us want to cause a warrr, I think it's best we step back and see what happens.
        I_M_NOT_GIVIN_UP_ON_PURGONORGO_ISLE                                                = 12944,  -- I'm not givin' up on Purgonorgo Isle, but it's smarrrter to let the Mithran Trackers handle this.
        WELL_ADVENTURER_HERRRE_S_A_LITTLE_SOMETHIN_FOR                                     = 12945,  -- Well, adventurer, herrre's a little somethin' for ya trouble. Thanks for ya help.
        ARRGH_IF_WINDURST_WASN_T_IN_CAHOOTS_WITH                                           = 12946,  -- Arrgh! If Windurst wasn't in cahoots with the Mithran pirates, we'd be able to get on with our battle!
        I_HAD_ME_NEXT_STRATEGY_ALL_WORKED_OUT                                              = 12947,  -- I had me next strategy all worked out fer kickin that warmachine right off the island!
        NOW_JUST_A_SECOND_THERE_MATEY_WHO_WAS                                              = 12948,  -- ...Now, just a second there, matey. Who was inside that warmachine, anyhow?
        ARRGH_A_NAME_SHOULDA_BEEN_WRITTEN_RIGHT_THERE                                      = 12949,  -- Arrgh! A name shoulda been written right there on the deed! I just can't remember...!
        HEY_YOU_RE_AN_ADVENTURER_RIGHT_YOU_RE                                              = 12950,  -- Hey! You're an adventurer, right? You're supposed to help people with stuff, right? Take this letter to that [cool guy/cute lady] in the red hat, okay?
