        CURRENT_STANDINGS_TEAM_SAN_D_ORIA_TEAM_BASTOK_2                                    = 15055,  -- `Current Standings` Team San d'Oria: [Dominant/Major/Minor/Minimal/???] Team Bastok: [Dominant/Major/Minor/Minimal/???] Team Windurst: [Dominant/Major/Minor/Minimal/???]
        CURRENT_STANDINGS_THREE_NATION_DEADLOCK_2                                          = 15056,  -- `Current Standings` Three-nation deadlock!
