        INNINGS_BREAKDOWN_BASE_GIL_PLUS_A_GIL_BONUS                                        = 15069,  -- innings Breakdown # base gil plus a #-gil bonus # [chocobuck/chocobucks] # [solo victory point/solo victory points]
        TURN_IN_YOUR_YES_NO                                                                = 15070,  -- Turn in your %? Yes. No.
