        ALRIGHTY_THEN_OUR_NEXT_RACE_FEATURES_OF_VANA                                       = 15200,  -- Alrighty then, our next race features # of Vana'diel's top chocobos. Let us start off by introducing the birds and their jockeys.
        FIRST_WE_HAVE_WHO_WILL_BE_RIDDEN_BY                                                = 15201,  -- First we have %, who will be ridden by [the ace of the chase, Ignazio/three-time chocobo racing alltar, Eudocia/the bloody emperor, Roinolier/the empress of speed, Maurette/Lami-Baami Suave Esquire III/the red rose of racing, Sosopapa/CRA legend, Khowa Mathgalhi/rising CRA star, Bayansh].
