        SHE_SAYS_THIS_JOCKEY_DOESN_T_GET_HIS                                               = 15205,  -- She says, This jockey doesn't get his name because he yields to through traffic, if you know what I mean.
        SHE_SAYS_THERE_ISN_T_A_JOCKEY_IN                                                   = 15206,  -- She says, There isn't a jockey in Vana'diel who loves her steed more than the empress of speed.
        SHE_SAYS_THIS_HEART_THROB_TREATS_HIS_MOUNTS                                        = 15207,  -- She says, This heart-throb treats his mounts like he treats his women--with an unparalleled sense of grace, a sixth sense, you could say.
        SHE_SAYS_SOSOPAPA_HAS_GOT_THE_MOVES_TO                                             = 15208,  -- She says, Sosopapa has got the moves to make even the stiffest of necks turn.
