        SELET_A_JOB_NEVER_MIND_WARRIOR_MONK_WHITE                                          = 15714,  -- Selet a job. Never mind. Warrior. Monk. White Mage. Black Mage. Red Mage. Thief. Paladin. Dark Knight. Beastmaster. Bard. Ranger. Samurai. Ninjaa. Dragoon. Summoner. Blue Mage. Corsair. Puppetmaster. Dancer. Scholar. Geomancer. Rune Fencer.
        GREETINGS_FRIEND_I_AM_A_SYNERGY_ENGINEER_DISPATCHED                                = 15715,  -- Greetings, friend! I am a synergy engineer, dispatched from the Institute to maintain the furnaces you see beside me. I also have knowledge and services to share with fellow synergists, if that is what you desire.
        I_SEE_FROM_THE_PUZZLED_EXPRESSION_ON_YOUR                                          = 15716,  -- I see from the puzzled expression on your face that you are unfamiliar with our discipline. To use these furnaces, you will first need to obtain %.
        PIQUED_YOUR_CURIOSITY_HAVE_I_THEN_YOU_SHOULD                                       = 15717,  -- Piqued your curiosity, have I? Then you should speak with Hildolf, our institute director, at his laboratory in the Bastok Metalworks. He's always eager to welcome a new synergist to our ranks.
        MAY_I_BE_OF_SERVICE_NOT_NOW_LEARN                                                  = 15718,  -- May I be of service? Not now. Learn recipes. Check fewell. Replenish fewell. Purchase materials. Receive training. Trade cinder. Get information.
        RECIPES_YOU_SAY_LET_S_SEE_WHAT_WE                                                  = 15719,  -- Recipes, you say? Let's see what we have that's suitable for your level of expertise...
        I_M_SORRY_I_M_AFRAID_THERE_S                                                       = 15720,  -- ...I'm sorry. I'm afraid there's nothing I can teach you at the moment.
        I_VE_GOT_IT_HOW_ABOUT_MIND_YOU                                                     = 15721,  -- I've got it! How about %? Mind you, it'll require a certain level of skill...
        SYNERGY_SKILL                                                                      = 15722,  -- Synergy skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran].
        SKILL                                                                              = 15723,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
        SKILL_SKILL                                                                        = 15724,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
        SKILL_SKILL_SKILL                                                                  = 15725,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
