        THE_RESISTANCE_GREATLY_VALUES_YOUR_CONTRIBUTIONS_TAKE_THIS                         = 16012,  -- The resistance greatly values your contributions. Take this as a small token of our appreciation, and do not hesitate to return the next time you are willing to lend your support.
