        SHOULDST_THY_JOURNEY_TAKE_THEE_TO_ANOTHER_NATION                                   = 16061,  -- Shouldst thy journey take thee to another nation, my kindred spirits in either [Northern San d'Oria/Port Bastok/Port Windurst] or [Northern San d'Oria/Port Bastok/Port Windurst] would also suffice.
        MAY_THE_WINDS_BLOW_THY_WAY_ADVENTURER                                              = 16062,  -- May the winds blow thy way, adventurer.
