        WAIT_BUT_A_MOMENT_HERE_FOLLOW_THIS_COMMAND                                         = 16231,  -- Wait but a moment. Here, follow this command--er, compendium to the letter and you should be able to learn a thing or two.
        AH_THIS_ALMOST_SLIPPED_MY_MIND_SHOULD_YOU                                          = 16232,  -- Ah, this almost slipped my mind. Should you receive any distinct sorts of artifacts for completing an objective, I will be happy to take them off your hands.
