        MOG_GARDENS_ARE_LOVELY_LOCALES_THAT_LIE_LATENT                                     = 16340,  -- Mog Gardens are lovely locales that lie latent in the west, on the Adoulin Islands. They're true treasure troves of taintless resources, frothing with fish, bursting with birds, and filled with forests, kupo!
        THINK_OF_IT_AS_YOUR_MOG_HOUSE_AWAY                                                 = 16341,  -- Think of it as your Mog House away from home! Just like that fantastic facility, there's a wealth of wonders just waiting to well up for your disposal.
        SPREAD_YOUR_WINGS_AS_WIDE_AS_YOU_WISH                                              = 16342,  -- Spread your wings as wide as you wish without worrying about the consequences, kupo. The Green Thumb Moogle will handle the husbandry of this homestead while you're out hacking at hordes of hellions and cavorting across continents.
        IF_YOU_RE_SHIVERING_TO_SHOVE_OFF_THEN                                              = 16343,  -- If you're shivering to shove off, then shuffle aboard the Mog Dinghy over there! It may seem small and slightly slipshod, but the mysterious moogle magic we manifest upon it is magnificent enough to move you malms and malms in mere minutes.
        ONCE_YOU_ADJUST_TO_YOUR_ADOULINIAN_ASYLUM_I                                        = 16344,  -- Once you adjust to your Adoulinian asylum, I'll even proffer printed publications that will make your Mog Garden more majestic. Grab your gil and get ready, kupo!
        WHILE_IT_D_BE_WICKEDLY_WONDERFUL_TO_WHISK                                          = 16345,  -- While it'd be wickedly wonderful to whisk away everyone to Mog Gardens, only Certified Adventurers and pioneers are allowed entry to these excellent expanses of escape, kupo.
        CERTIFIED_ADVENTURERS_ARE_THOSE_WHO_HAVE_APPLIED_THEMSELVES                        = 16346,  -- Certified Adventurers are those who have applied themselves assiduously, attaining the third mission rank in any nation.
        IT_DOESN_T_HAVE_TO_BE_HERE_AS                                                      = 16347,  -- It doesn't have to be here as long as you were once appropriately accredited in times antecedent.
