        BY_GOING_TO_MAIN_MENU_CONFIG_MISC_2                                                = 16862,  -- ...by going to Main Menu > Config > Misc. 2 > Key Assignment > Commands > Chat: /AssistE or /AssistJ.
        IT_IS_RECOMMENDED_THAT_YOU_USE_ASSISTJ_AJ                                          = 16863,  -- It is recommended that you use /assistj (/aj) when posting in Japanese, and /assiste (/ae) when posting in English.
        YOU_MUST_MEET_ONE_OF_THE_FOLLOWING_CONDITIONS                                      = 16864,  -- You must meet one of the following conditions in order to post to the Assist Channel.
        ID_1_YOU_ARE_A_NEW_PLAYER_YOU_MAY                                                  = 16865,  -- 1. You are a new player You may post messages from the moment you first set foot in Vana'diel.
        ID_2_YOU_ARE_A_RETURNEE_AS_A_RETURNING                                             = 16866,  -- 2. You are a returnee As a returning player, you may post messages upon logging in with a character that has not logged in for at least 48 days.
        ID_3_YOU_ARE_A_MENTOR_YOU_MAY_POST                                                 = 16867,  -- 3. You are a mentor You may post messages as long as you remain a mentor to other players.
        NEW_PLAYERS_AND_RETURNEES_MAY_POST_MESSAGES_UNTIL                                  = 16868,  -- New players and returnees may post messages until they have been logged in for a total of 48 hours since first receiving their posting rights.
        IF_YOU_WISH_TO_CHECK_HOW_LONG_YOU                                                  = 16869,  -- If you wish to check how long you can continue to post for, speak to an and choose "When do my posting rights expire?" to see how much time you have left.
        THE_ASSIST_CHANNEL_CAN_ONLY_BE_USED_IN                                             = 16870,  -- The Assist Channel can only be used in the following areas.
