        PLEASE_USE_THIS_FEATURE_WHEN_A_POST_S                                              = 16889,  -- Please use this feature when a post's contents are insufficient or otherwise may be construed as harassment.
        TO_SEND_A_THUMBS_UP_OR_WARNING_TO                                                  = 16890,  -- To send a Thumbs Up or Warning to another player, open the Chat Log Window and move the cursor over the relevant message and press the confirm button (Enter key) to bring up the evaluation menu.
